#!/usr/bin/env node
/**
 * Regenerates js/symptom-icons.js from symptoms/*.svg.
 * Run: npm run generate-symptom-icons
 */
const fs = require('fs');
const path = require('path');

const SYMPTOM_KEYS = [
  'cramps', 'headache', 'fatigue', 'bloating', 'mood', 'backPain',
  'breastTenderness', 'nausea', 'acne', 'cravings', 'insomnia', 'flowHeavy',
];

const root = path.resolve(__dirname, '..');
let out = `/**
 * Symptom SVG icons — from symptoms/*.svg, inlined for currentColor support.
 * Keys match SYMPTOM_KEYS from metrics.js.
 * Generated by: npm run generate-symptom-icons
 */
export const SYMPTOM_SVGS = {
`;

for (const key of SYMPTOM_KEYS) {
  const fp = path.join(root, 'symptoms', key + '.svg');
  if (!fs.existsSync(fp)) continue;
  let content = fs.readFileSync(fp, 'utf8');
  content = content.replace(/<\?xml[^>]*\?>[\s\S]*?<svg/s, '<svg');
  content = content.replace(/\s+/g, ' ').trim();
  const escaped = content.replace(/\\/g, '\\\\').replace(/`/g, '\\`');
  out += `  ${key}: \`${escaped}\`,\n`;
}

out += '};\n';
fs.writeFileSync(path.join(root, 'js', 'symptom-icons.js'), out);
console.log('Generated js/symptom-icons.js');
console.log('Keys:', SYMPTOM_KEYS.filter(k => fs.existsSync(path.join(root, 'symptoms', k + '.svg'))).join(', '));
